args.sparql:
SELECT ?artist ?nationality WHERE {
  ?series wdt:P506 17.
  ?episode wdt:P361 ?series;
          wdt:P547 7.
  ?performance wdt:P1557 ?episode.
  ?performance wdt:P549 ?score.
  ?performance wdt:P175 ?song.
  ?song wdt:P4191 ?artist.
  ?artist wdt:P27 ?nationality.
} ORDER BY ASC(?score) LIMIT 1

SELECT ?artist ?nationality WHERE {
  ?episode wdt:P179 wd:Q5255868 ;
           wdt:P547 7 .
